@dataclass
class EcgRecord:
    Fs: list[int]
    Signals: np.array([float])
    Leads: list[str]
    Units: list[str]
    Metadata: dict[str:str]
    SAECG_EPOCHS: list[np.array([np.array([float])])] = None
    pSAECG_EPOCS: list[np.array([np.array([float])])] = None
    SAECG: list[np.array([float])] = None
    pSAECG: list[np.array([float])] = None
    SAECG_avg_method: str = None
    pSAECG_avg_method: str = None
    SAECG_prep_method: str = None
    pSAECG_prep_method: str = None
    SAECG_relatively_r_peaks_location: dict[str:int] = None
    pSAECG_relatively_r_peaks_location: dict[str:int] = None


    def saecg_count(self, all_leads_peaks_average=True, avg_method='avg', remove_strange_cardiocycles = True,
                    preprocessing = 'butter_filter', only_lp = False):
        saecg_mass = []
        saecg_epochs = []
        averaged_r_peaks_list = None
        saecg_peak_dict = None
        if all_leads_peaks_average:
            averaged_r_peaks_list = self.average_peaks_by_all_leads(self.Signals, self.Fs[0])
        for signal, fs in zip(self.Signals, self.Fs):
            complex_averaged, complex_epochs, saecg_peak_dict = self.saecg_complex(signal, fs, r_peaks=averaged_r_peaks_list,
                                                                  filt_50_hz=False, filt_100_hz=False, filt_60_hz=False,
                                                                  filt_120_hz=False, avg_method=avg_method,
                                                                  remove_outliers= remove_strange_cardiocycles,
                                                                  preprocessing=preprocessing, only_lp=only_lp)
            if np.isnan(complex_averaged).all():
                complex_averaged = [0, 0, 0]
            else:
                complex_averaged = list(complex_averaged)

            saecg_mass.append(complex_averaged)
            saecg_epochs.append(complex_epochs)
        self.SAECG = saecg_mass
        self.SAECG_avg_method = avg_method
        self.SAECG_prep_method = preprocessing
        self.SAECG_EPOCHS = saecg_epochs
        self.SAECG_relatively_r_peaks_location = saecg_peak_dict
        return self

    def psaecg_count(self, all_leads_p_peaks_averaged=True, avg_method='avg', remove_strange_cardiocycles = True,
                     preprocessing = 'butter_filter', only_lp=False):
        psaecg_mass = []
        psaecg_epochs = []
        averaged_p_peaks_list = None
        psaecg_peak_dict = None
        if all_leads_p_peaks_averaged:
            try:
                averaged_p_peaks_list = self.average_p_peaks_by_all_leads(self.Signals, self.Fs[0])
            except:
                pass
        for signal, fs in zip(self.Signals, self.Fs):
            complex_averaged, complex_epochs, psaecg_peak_dict = self.psaecg_complex(signal, fs, p_peaks=averaged_p_peaks_list,
                                                                   filt_50_hz=False, filt_100_hz=False,
                                                                   filt_60_hz=False,
                                                                   filt_120_hz=False, avg_method=avg_method,
                                                                   remove_outliers=remove_strange_cardiocycles,
                                                                   preprocessing=preprocessing, only_lp=only_lp)
            if np.isnan(complex_averaged).all():
                complex_averaged = [0, 0, 0]
            else:
                complex_averaged = list(complex_averaged)

            psaecg_mass.append(complex_averaged)
            psaecg_epochs.append(complex_epochs)
        self.pSAECG = psaecg_mass
        self.pSAECG_avg_method = avg_method
        self.pSAECG_prep_method = preprocessing
        self.pSAECG_EPOCS = psaecg_epochs
        self.pSAECG_relatively_r_peaks_location = psaecg_peak_dict
        return self

    def ged_record_len(self):
        len_dict = {'Unit': 'sec'}
        for lead_name, signal, fs in zip(self.Leads, self.Signals, self.Fs):
            len_dict[lead_name] = len(signal) / fs
        return len_dict

    def remove_leads(self, *lead_to_remove: [str]):
        new_fs_mass = []
        new_signals_mass = []
        new_leads_mass = []
        new_units_mass = []
        for fs, signal, lead, unit in zip(self.Fs, self.Signals, self.Leads, self.Units):
            if lead in lead_to_remove:
                pass
            else:
                new_fs_mass.append(fs)
                new_signals_mass.append(signal)
                new_leads_mass.append(lead)
                new_units_mass.append(unit)

        self.Fs = new_fs_mass
        self.Signals = new_signals_mass
        self.Leads = new_leads_mass
        self.Units = new_units_mass
        return self

    def plot_saecg(self):
        for fs, signal, lead, unit, saecg_epoch, psaecg_epoch, saecg, psaecg in zip(
            self.Fs, self.Signals, self.Leads, self.Units, self.SAECG_EPOCHS, self.pSAECG_EPOCS,
            self.SAECG, self.pSAECG):

            plt.figure()
            plt.suptitle('SAECG + pSAECG (avg_method:' +
                         str(self.SAECG_avg_method) +', preprocessing: '+str(self.SAECG_prep_method)+ ')')
            t_vector = np.array(list(range(len(signal))))/fs

            #------------------------Input signal ---------------------------
            input_sig = plt.subplot(3,1,1)
            input_sig.plot(t_vector, signal)
            input_sig.set_title('Input signal',fontsize=10)
            input_sig.set_xlabel('time[sec]', fontsize=7)
            input_sig.set_ylabel('amplitude [uV]', fontsize=7)
            plt.xticks(fontsize=7, rotation=None)
            plt.yticks(fontsize=7, rotation=None)

            #--------------------------Saecg_epochs--------------------------
            saecg_epochs_plot = plt.subplot(3,2,3)
            print('SAECG epochs size: ' + str(len(saecg_epoch)))
            for cycle in saecg_epoch:
                saecg_epochs_plot.plot(cycle)
            saecg_epochs_plot.set_title('SAECG epochs',fontsize=10)
            saecg_epochs_plot.set_xlabel('samples', fontsize=7)
            saecg_epochs_plot.set_ylabel('amplitude [uV]', fontsize=7)
            plt.xticks(fontsize=7, rotation=None)
            plt.yticks(fontsize=7, rotation=None)

            #---------------------------Saecg--------------------------------
            saecg_epochs_plot = plt.subplot(3, 2, 5)
            saecg_epochs_plot.plot(saecg)
            saecg_epochs_plot.set_title('SAECG', fontsize=10)
            saecg_epochs_plot.set_xlabel('samples', fontsize=7)
            saecg_epochs_plot.set_ylabel('amplitude [uV]', fontsize=7)
            plt.xticks(fontsize=7, rotation=None)
            plt.yticks(fontsize=7, rotation=None)

            # --------------------------pSaecg_epochs--------------------------
            saecg_epochs_plot = plt.subplot(3, 2, 4)
            print('pSAECG epochs size: ' + str(len(psaecg_epoch)))
            for cycle in psaecg_epoch:
                saecg_epochs_plot.plot(cycle)
            saecg_epochs_plot.set_title('pSAECG epochs', fontsize=10)
            saecg_epochs_plot.set_xlabel('samples', fontsize=7)
            saecg_epochs_plot.set_ylabel('amplitude [uV]', fontsize=7)
            plt.xticks(fontsize=7, rotation=None)
            plt.yticks(fontsize=7, rotation=None)

            # ---------------------------pSaecg--------------------------------
            saecg_epochs_plot = plt.subplot(3, 2, 6)
            saecg_epochs_plot.plot(psaecg)
            saecg_epochs_plot.set_title('pSAECG', fontsize=10)
            saecg_epochs_plot.set_xlabel('samples', fontsize=7)
            saecg_epochs_plot.set_ylabel('amplitude [uV]', fontsize=7)
            plt.xticks(fontsize=7, rotation=None)
            plt.yticks(fontsize=7, rotation=None)

            plt.show()
            input('ss')

    @staticmethod
    def rr_interval_counter(r_peaks_masss):
        peak_count = -1
        rr_intervals_mass = []
        while peak_count + 3 <= len(r_peaks_masss):
            peak_count = peak_count + 1
            rr_intervals_mass.append(r_peaks_masss[peak_count + 1] - r_peaks_masss[peak_count])
        return np.median(rr_intervals_mass)

    @staticmethod
    def cardiocycle_points_position_clarification(waves_peaks, r_peaks):
        # gives avg possition difference betwee R peak and each peak position
        peaks_keys = waves_peaks.keys()
        clarificated_peaks = {}
        r_peaks_position_mass = np.array(r_peaks['ECG_R_Peaks']).astype(int)
        rr_interval = EcgRecord.rr_interval_counter(r_peaks_position_mass)
        peaks_position_zone = round(rr_interval * 0.5)
        for peak_key in peaks_keys:
            peaaks_key_mass = np.array(waves_peaks[peak_key]).astype(int)
            peak_distance_mass = []
            for r_peak_pos in r_peaks_position_mass:
                peak_positions = peaaks_key_mass[np.where((peaaks_key_mass < (r_peak_pos + peaks_position_zone)) &
                                                          (peaaks_key_mass > (r_peak_pos - peaks_position_zone)))]
                peak_positions = list(peak_positions)
                if peak_positions:
                    if len(peak_positions) == 1:
                        peak_distance_mass.append(peak_positions[0] - r_peak_pos)
                    else:
                        continue
                else:
                    continue
            clarificated_peaks[peak_key] = np.median(peak_distance_mass)
        return clarificated_peaks

    @staticmethod
    def only_lp_select(input_qrs_epochs, input_signal, fs, mode = 'lvp'):
        signal_filtered = AnalogFilterDesign(input_signal, fs).lp(order=5, cutoff=20).zerophaze().butter() \
                .filtration()
        _, rpeaks = nk.ecg_peaks(signal_filtered,method=cardiocycles_detector_method, sampling_rate=fs)
        _, waves_peak = nk.ecg_delineate(signal_filtered,rpeaks, sampling_rate=fs,method="cwt", show=False, show_type='all')
        clarificated_peaks =EcgRecord.cardiocycle_points_position_clarification(waves_peak, rpeaks)
        averaged_complex = np.array(input_qrs_epochs).mean(axis=0)
        r_peak = EcgRecord.find_r_peak_on_qrs_complex(averaged_complex, fs)
        lap_startpos = int(r_peak + clarificated_peaks['ECG_P_Peaks'])
        lap_endpos = int(r_peak + clarificated_peaks['ECG_Q_Peaks'])

        lvp_startpos = int(r_peak+ clarificated_peaks['ECG_S_Peaks'])
        lvp_endpos = int(r_peak + clarificated_peaks['ECG_T_Peaks'])

        # print('pp')
        # plt.figure()
        # plt.plot(averaged_complex)
        # colorss = [
        #     '#1f77b4',  # muted blue
        #     '#ff7f0e',  # safety orange
        #     '#2ca02c',  # cooked asparagus green
        #     '#d62728',  # brick red
        #     '#9467bd',  # muted purple
        #     '#8c564b',  # chestnut brown
        #     '#e377c2',  # raspberry yogurt pink
        #     '#7f7f7f',  # middle gray
        #     '#bcbd22',  # curry yellow-green
        #     '#17becf'  # blue-teal
        # ]
        # for peak_key,color in zip(clarificated_peaks.keys(), colorss):
        #     plt.axvline(x=r_peak + clarificated_peaks[peak_key], label = peak_key, color=color)
        # plt.legend()
        # plt.show()

        start_pos = None
        end_pos = None
        if mode == 'lvp':
            start_pos = lvp_startpos
            end_pos = lvp_endpos
        elif mode == 'lap':
            start_pos = lap_startpos
            end_pos = lap_endpos
        else:
            TypeError('Not known mode:' + str(mode))

        new_lp_epochs = []
        for qrs_comp in input_qrs_epochs:
            lp_part = np.array(qrs_comp)[start_pos:end_pos]
            new_lp_epochs.append(lp_part)

        return np.array(new_lp_epochs), clarificated_peaks



