    @staticmethod
    def psaecg_complex(signal: np.ndarray[float], fs: [int], p_peaks: dict = None, avg_method: str = 'avg',
                       remove_outliers=True,preprocessing: str = 'butter_filter',
                       filt_50_hz=False, filt_100_hz=False, filt_60_hz=False, filt_120_hz=False, only_lp = False):

        signal_filtered = EcgRecord.saecg_filter(signal, fs, preprocessing=preprocessing)
        if filt_50_hz:
            signal_filtered = EcgRecord.stnphaze_50_hz_filter(signal_filtered, fs)
        if filt_60_hz:
            signal_filtered = EcgRecord.stnphaze_60_hz_filter(signal_filtered, fs)
        if filt_120_hz:
            signal_filtered = EcgRecord.stnphaze_120_hz_filter(signal_filtered, fs)
        if filt_100_hz:
            signal_filtered = EcgRecord.stnphaze_100_hz_filter(signal_filtered, fs)

        if p_peaks is not None:
            qrs_epochs = nk.ecg_segment(signal_filtered, sampling_rate=fs, rpeaks=p_peaks, show=False)
        else:
            p_peaks_mass = EcgRecord.find_p_peaks_mass(signal_filtered)
            if p_peaks_mass is not None:
                new_peaks_mass = []
                for value in p_peaks_mass:
                    if np.isnan(value):
                        pass
                    else:
                        new_peaks_mass.append(value)
                try:
                    qrs_epochs = nk.ecg_segment(signal_filtered, sampling_rate=fs,
                                                rpeaks=new_peaks_mass, show=False)
                except:
                    return [0,0,0], None, None
            else:
                return [0,0,0], None, None

        if remove_outliers:
            qrs_epochs = EcgRecord.remove_strange_cardiocycles(qrs_epochs)
        else:
            qrs_epochs = EcgRecord.qrs_epochs_list(qrs_epochs)

        try:
            lp_epochs, psaecg_peaks = EcgRecord.only_lp_select(qrs_epochs, signal, fs, mode='lap')
        except:
            lp_epochs = None
            psaecg_peaks = None
        if only_lp:
            qrs_epochs = lp_epochs

        averaged_complex = EcgRecord.average_qrs_epochs(qrs_epochs,fs, method=avg_method)
        complex_epochs = qrs_epochs
        return averaged_complex, complex_epochs, psaecg_peaks

