    @staticmethod
    def average_qrs_epochs(nk_epochs, fs, method=None):
        if method == 'avg':
            qrs_complex_averaged = np.array(nk_epochs).mean(axis=0)
        elif method == 'custom':
            qrs_complex_averaged = EcgRecord.custom_saecg_algorithm(nk_epochs, fs)
        else:
            raise TypeError('Not known method:' + str(method))

        return qrs_complex_averaged

    @staticmethod
    def find_r_peaks_mass(ecg_signal, fs):
        cleaned = nk.ecg_clean(ecg_signal, method="neurokit")
        _, peaks = nk.ecg_peaks(cleaned, method=cardiocycles_detector_method, sampling_rate=fs)
        return peaks["ECG_R_Peaks"]

    @staticmethod
    def find_p_peaks_mass(ecg_signal):
        cleaned = nk.ecg_clean(ecg_signal, method="neurokit")
        try:
            _, waves_peak = nk.ecg_delineate(cleaned, method="peak")
            return waves_peak['ECG_P_Peaks']
        except:
            return None

    @staticmethod
    def average_p_peaks_by_all_leads(signals, fs):
        p_peaks_for_each_lead = []
        for lead_signal in signals:
            p_peaks_for_each_lead.append(EcgRecord.find_p_peaks_mass(lead_signal))

        peaks_concated = np.concatenate(p_peaks_for_each_lead, axis=0)
        peaks_concated = peaks_concated[~np.isnan(peaks_concated)]
        max_peak_value = np.max(peaks_concated)
        positions_vector = list(range(0, int(max_peak_value) + int(np.round(fs / 2)), 1))
        all_positions_dict = {}
        for pos in positions_vector:
            all_positions_dict[pos] = 0
        for r_peaks_mass_lead in p_peaks_for_each_lead:
            for position in positions_vector:
                if position in r_peaks_mass_lead:
                    all_positions_dict[position] += 1
        results_filtered = AnalogFilterDesign(list(all_positions_dict.values()),
                                              fs).lp(order=5, cutoff=8).zerophaze().butter().filtration()
        _, averaged_p_peaks_responce = nk.ecg_peaks(results_filtered, method=cardiocycles_detector_method, sampling_rate=fs)
        averaged_p_peaks_responce = averaged_p_peaks_responce["ECG_R_Peaks"]
        return averaged_p_peaks_responce

